export const ZONE_SESSION_NET_STRIDE = 8;
export const ZONE_SESSION_NET_SCHEMA_HASH = 0xd3c380be6e350328n;

export class ZoneSessionNetBatchView {
  readonly count: number;
  readonly payload: Uint8Array;

  constructor(readonly bytes: Uint8Array) {
    this.count = readNetHeader(
      bytes,
      ZONE_SESSION_NET_SCHEMA_ID,
      ZONE_SESSION_NET_VERSION,
      ZONE_SESSION_NET_SCHEMA_HASH,
      ZONE_SESSION_NET_STRIDE
    );
    this.payload = bytes.subarray(NET_HEADER_BYTES);
  }

  record(index: number): ZoneSessionNetView {
    assertRecordIndex(index, this.count);
    return new ZoneSessionNetView(
      this.bytes.buffer,
      this.bytes.byteOffset + NET_HEADER_BYTES + index * ZONE_SESSION_NET_STRIDE
    );
  }
}

export function createZoneSessionNetBatch(
  count: number,
  target?: Uint8Array
): ZoneSessionNetBatchView {
  const bytes = createNetPacket(
    ZONE_SESSION_NET_SCHEMA_ID,
    ZONE_SESSION_NET_VERSION,
    ZONE_SESSION_NET_SCHEMA_HASH,
    ZONE_SESSION_NET_STRIDE,
    count,
    target
  );
  return new ZoneSessionNetBatchView(bytes);
}

export function viewZoneSessionNet(
  bytes: Uint8Array,
  index = 0
): ZoneSessionNetView | null {
  try {
    return new ZoneSessionNetBatchView(bytes).record(index);
  } catch {
    return null;
  }
}

export function encodeZoneSessionNet(
  value: Readonly<ZoneSessionNet>,
  target?: Uint8Array
): Uint8Array {
  const batch = createZoneSessionNetBatch(1, target);
  writeZoneSessionNet(batch.record(0), value);
  return batch.bytes;
}

export function decodeZoneSessionNet(bytes: Uint8Array): ZoneSessionNet | null {
  const view = viewZoneSessionNet(bytes);
  return view ? readZoneSessionNet(view) : null;
}

